from collections import Counter

def find_anagrams(s, p):
    if len(p) > len(s):
        return []

    p_count, win_count = Counter(p), Counter()
    result = []

    for i in range(len(s)):
        win_count[s[i]] += 1
        if i >= len(p):
            if win_count[s[i - len(p)]] == 1:
                del win_count[s[i - len(p)]]
            else:
                win_count[s[i - len(p)]] -= 1
        if win_count == p_count:
            result.append(i - len(p) + 1)

    return result
